// フローにキューを保持
let queues = flow.get("queues") || {};

let msgBody = msg.payload;
let dest = msgBody.dest;

if(!queues[dest]){
    queues[dest] = [];
}
queues[dest].push(msgBody);
flow.set("queues", queues);

msg.payload = {status: "ok"};
return msg;

let queues = flow.get("queues") || {};
let party_id = msg.req.params.party_id;

let msgs = queues[party_id] || [];
// queues[party_id] = [];
// flow.set("queues", queues);

msg.payload = msgs;
return msg;

// const elliptic = require('elliptic');
// const crypto = require('crypto');
const ec = new elliptic.ec('secp256k1');

// フロー変数から公開鍵を取り出す
const pubX = flow.get("pubX");
const pubY = flow.get("pubY");

const originalData = "0123456789abcdef";
// const originalData = flow.get("originalData");

// 2. 元データのハッシュを計算する
// const msgHash = crypto.createHash('sha256').update(originalData).digest();
const msgHash = originalData;

// 3. 署名データと公開鍵をセット
const pubKey = { x: pubX, y: pubY };
const signature = { r: msg.payload.signature.r, s: msg.payload.signature.s };

try {
    const key = ec.keyFromPublic(pubKey, 'hex');

    // 4. 計算したハッシュを使って署名を検証
    const isValid = key.verify(msgHash, signature);

    msg.payload = {
        isValid: isValid, // これが true なら「元データ」は1文字も改ざんされていない！
        // verifiedHash: msgHash.toString('hex')
        verifiedHash: msgHash
    };
} catch (e) {
    node.error(e.message);
}

return msg;

let data = msg.payload;

let rows = [];

let bc = data.bc ? data.bc.slice(0,16) + "..." : null;
let p2p = data.p2p ? data.p2p.slice(0,16) + "..." : null;

// bc がある場合
if (bc) {
    rows.push({
        round: data.round,
        src: data.src,
        dest: data.dest,
        type: "broadcast",
        data: bc
    });
}

// p2p がある場合
if (p2p) {
    rows.push({
        round: data.round,
        src: data.src,
        dest: data.dest,
        type: "p2p",
        data: p2p
    });
}

msg.payload = rows;

return msg;

let table = flow.get("table") || [];

table = table.concat(msg.payload);

if (table.length > 100) {
    table = table.slice(-100);
}

flow.set("table", table);

msg.payload = table;

return msg;

let table = msg.payload;

if (table.length === 0) return null;

// 最新イベント
let last = table[table.length - 1];

msg.payload = {
    src: last.src,
    dest: last.dest,
    type: last.type
};

return msg;

let e = msg.payload;

msg.payload = {
    nodes: [
        {id: "co_signer1", label: "co_signer1"},
        {id: "co_signer2", label: "co_signer2"},
        {id: "co_signer3", label: "co_signer3"}
    ],
    edges: [
        {
            from: e.src,
            to: e.dest,
            color: e.type === "broadcast" ? "orange" : "cyan",
            width: 4
        }
    ]
};

return msg;
